from flask import Flask, request, jsonify
from collections import defaultdict, Counter
from sklearn.model_selection import train_test_split
from sklearn.linear_model import LogisticRegression
import numpy as np

app = Flask(__name__)

# Dummy data structures for demonstration
image_labels = defaultdict(list)  # Store labels for each image
images = []  # List of image data placeholders

@app.route('/submit_label', methods=['POST'])
def submit_label():
    data = request.json
    image_id = data['image_id']
    label = data['label']
    image_labels[image_id].append(label)
    return jsonify({"message": "Label received"}), 200

def aggregate_labels():
    aggregated_labels = {}
    for image_id, labels in image_labels.items():
        label = Counter(labels).most_common(1)[0][0]
        aggregated_labels[image_id] = label
    return aggregated_labels

def train_model(images, labels):
    X = np.array(images)  # Replace with actual image feature extraction
    y = np.array(labels)
    model = LogisticRegression()
    model.fit(X, y)
    return model

def run_system():
    aggregated_labels = aggregate_labels()
    train_images = [img for img_id, img in enumerate(images) if img_id in aggregated_labels]
    train_labels = [label for img_id, label in aggregated_labels.items()]
    model = train_model(train_images, train_labels)
    return model

if __name__ == '__main__':
    app.run(port=5000)